// Castle Tower — grand medieval stone tower with voronoi stone texture
// Z-up, tower centered at X=0 Y=0, base at Z=0
// Total height: ~44mm (base 2 + tower 27 + parapet 3 + merlons 3 + roof 11)

const { Manifold, CrossSection } = api;

// === DIMENSIONS ===
const towerR       = 9.0;    // main tower radius
const baseR        = 11.0;   // battered base ring radius
const baseH        = 2.0;    // base ring height
const towerH       = 27.0;   // tower body height (above base)
const parapetR     = 9.8;    // parapet ring slightly wider
const parapetH     = 2.5;    // parapet ring height (slightly taller)
const parapetZ     = baseH + towerH;
const merlonH      = 3.2;    // merlon height above parapet top (taller for prominence)
const roofBaseR    = 8.8;    // cone base fits INSIDE the parapet ring
const roofZ        = parapetZ + parapetH - 0.2;
const roofH        = 11.5;   // cone height

// === BASE (battered, wider at bottom) ===
const base = Manifold.cylinder(baseH, baseR, towerR + 0.3, 64);

// === TOWER BODY (slight taper) ===
const towerBody = Manifold.cylinder(towerH + 0.5, towerR, towerR - 0.5, 64)
  .translate([0, 0, baseH - 0.5]);

// === PARAPET RING ===
const parapetRing = Manifold.cylinder(parapetH, parapetR, parapetR, 64)
  .translate([0, 0, parapetZ]);

// === CRENELLATIONS — 8 merlons ===
// Each merlon: a thick block placed radially at the parapet top.
// The block's radial (depth) dimension spans the full parapet thickness plus a bit extra.
// Its tangential width is ~50% of the sector arc length.
const numMerlons    = 8;
const sectorAng     = 360 / numMerlons;   // 45°
const merlonArcFrac = 0.50;               // merlon uses 50% of arc
const merlonZ       = parapetZ + parapetH;

// Arc chord length at parapetR
const arcLen        = 2 * Math.PI * parapetR * (merlonArcFrac / numMerlons);
const merlonWidth   = arcLen;             // tangential size
const merlonDepth   = 2.8;               // radial size
const merlonCenterR = parapetR - merlonDepth / 2 + 0.4;  // radial placement

let merlons = [];
for (let i = 0; i < numMerlons; i++) {
  const angle = i * sectorAng;
  // Box: depth × width × height, centered on the parapet ring perimeter
  const merlon = Manifold.cube([merlonDepth + 0.6, merlonWidth, merlonH + 0.5])
    .translate([
      merlonCenterR - (merlonDepth + 0.6) / 2,
      -merlonWidth / 2,
      merlonZ - 0.5  // overlap 0.5 into parapet top for guaranteed union
    ])
    .rotate([0, 0, angle]);
  merlons.push(merlon);
}
const allMerlons = Manifold.union(merlons);

// === STONE BODY ===
const stoneSolid = Manifold.union([base, towerBody, parapetRing, allMerlons]);

// === DOOR — Gothic arch on -Y face ===
const doorW  = 3.4;
const doorH  = 6.0;
const archR  = doorW / 2;

const doorRect  = CrossSection.square([doorW, doorH - archR])
  .translate([-doorW / 2, 0]);
const doorArc   = CrossSection.circle(archR, 24).translate([0, doorH - archR]);
const doorShape = CrossSection.union([doorRect, doorArc]);

// Extrude well past wall to punch clean through
const doorCutter = Manifold.extrude(doorShape, 6.0)
  .rotate([90, 0, 0])
  .translate([0, -towerR - 2.5, baseH + 0.5]);

// Door frame: arch molding on the outside of the tower
// Starts inside tower surface so it boolean-unions correctly
const frameW  = doorW + 1.6;
const frameH  = doorH + 1.0;
const frameR  = frameW / 2;
const frameRect2 = CrossSection.square([frameW, frameH - frameR])
  .translate([-frameW / 2, 0]);
const frameArc2  = CrossSection.circle(frameR, 24).translate([0, frameH - frameR]);
const frameShape = CrossSection.union([frameRect2, frameArc2]);

// depth 2.0mm: starts 1.0mm inside surface, protrudes 1.0mm outward
const doorFrame = Manifold.extrude(frameShape, 2.0)
  .rotate([90, 0, 0])
  .translate([0, -(towerR - 1.0), baseH + 0.3]);

// === ARROW SLIT WINDOWS — 3 narrow vertical slots ===
const slitW = 0.9;
const slitH = 4.2;
const slitD = 5.5;  // more than 2×wall thickness to ensure clean cut

function makeSlitCutter(zCenter, angle) {
  return Manifold.cube([slitW, slitD, slitH])
    .translate([-slitW / 2, -towerR - 2.0, zCenter - slitH / 2])
    .rotate([0, 0, angle]);
}

// 3 windows at distinct angles (away from door at 0°)
const slit1 = makeSlitCutter(baseH + 9.0,   72);
const slit2 = makeSlitCutter(baseH + 17.5, -72);
const slit3 = makeSlitCutter(baseH + 24.0,  135);
const allSlits = Manifold.union([slit1, slit2, slit3]);

// Arrow slit frames: thin raised border around each slit
// The frame is a slightly wider/taller cube, shallower protrusion
// It starts 1.5mm INSIDE the tower surface so it's always fused
function makeSlitFrame(zCenter, angle) {
  const fw = slitW + 1.6;   // slightly wider than slit
  const fh = slitH + 1.6;   // slightly taller than slit
  const fd = 1.4;           // thin — only 0.4mm protrusion beyond surface (1.4 - 1.0 inside)
  const frameInner = towerR - 1.0;  // inner edge is 1.0mm inside tower surface
  return Manifold.cube([fw, fd, fh])
    .translate([-fw / 2, -(frameInner + fd), zCenter - fh / 2])
    .rotate([0, 0, angle]);
}

const frame1 = makeSlitFrame(baseH + 9.0,   72);
const frame2 = makeSlitFrame(baseH + 17.5, -72);
const frame3 = makeSlitFrame(baseH + 24.0,  135);
const allSlitFrames = Manifold.union([frame1, frame2, frame3]);

// Union frames into stone body FIRST, then cut openings
const stoneWithFrames   = Manifold.union([stoneSolid, allSlitFrames]);
const stoneWithOpenings = stoneWithFrames
  .subtract(doorCutter)
  .subtract(allSlits);

// === CONICAL ROOF ===
// The roof fits inside the parapet ring top — merlons rise above the roof base
const roofCone = Manifold.cylinder(roofH, roofBaseR, 0.15, 64)
  .translate([0, 0, roofZ]);

// === LABEL PARTS ===
const stoneLabeled = api.label(stoneWithOpenings, 'stone',    { color: '#8a8a8a' });
const roofLabeled  = api.label(roofCone,          'roof',     { color: '#1e3a7a' });
const frameLabeled = api.label(doorFrame,         'woodwork', { color: '#3d2610' });

// === ASSEMBLE ===
const assembled = Manifold.union([stoneLabeled, roofLabeled, frameLabeled]);

// === VORONOI STONE TEXTURE ===
api.surface.voronoi({
  amplitude: 0.52,
  cellSize: 7,
  wallWidth: 0.55,
  jitter: 0.65,
  quality: 0.5,
  label: 'stone'
});

return assembled;
